document.addEventListener("DOMContentLoaded",(function(){const e=document.getElementById("proyphresia_se_eth"),t=document.getElementById("proyphresia_se_mhnes"),n=document.getElementById("hmeromhnia_proslhpshs"),a=document.getElementById("misthologiko_klimakio");function calculateTotalExperience(){const o=new Date,l=new Date(n.value);let s=o.getFullYear()-l.getFullYear(),c=o.getMonth()-l.getMonth();o.getDate()<l.getDate()&&c--,c<0&&(s--,c+=12);const r=parseInt(e.value,10),d=parseInt(t.value,10);let i=parseInt(s,10)+parseInt(r,10),u=parseInt(c,10)+parseInt(d,10);u>=12&&(i+=Math.floor(u/12),u%=12),12===u&&(i+=1,u=0),i<0&&(i=0),document.getElementById("synolo_proyphresias_se_eth").value=i||0,document.getElementById("synolo_proyphresias_se_mhnes").value=u||0,function updateMisthologikoKlimakio(e,t,n){let o=1;e>=1&&(o=e+1),a.value=o}(i)}e.addEventListener("change",calculateTotalExperience),t.addEventListener("change",calculateTotalExperience),n.addEventListener("change",calculateTotalExperience)}));